*{margin:0;padding:0;box-sizing:border-box}
  :root{--bg:#0d1117;--surface:#161b22;--border:#30363d;--text:#c9d1d9;--dim:#8b949e;--accent:#58a6ff;--user:#1f6feb;--ma:#238636;--err:#f85149;--hover:rgba(255,255,255,.05);--menu-bg:#11161d;--toolbar-bg:#161b22;--shell-bg:#0b1016;--panel-bg:#151b23;--editor-bg:#0f141b;--editor-top:#131922;--editor-head:#121821;--chat-bg:#131922;--chat-head:#161d27;--input-bg:rgba(22,27,34,.92);--preview-bg:rgba(255,255,255,.02);--preview-code-bg:#0b1016;--ide-gutter:#7d8590;--ide-line-highlight:rgba(88,166,255,.06);--tok-keyword:#ff7b72;--tok-string:#a5d6ff;--tok-comment:#8b949e;--tok-number:#79c0ff;--tok-function:#d2a8ff;--tok-type:#ffa657;--tok-tag:#7ee787;--tok-attr:#d2a8ff;--tok-operator:#f2cc60}
  html,body{height:100%;overflow:hidden}
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:var(--bg);color:var(--text);display:flex;flex-direction:column;color-scheme:dark}
  body[data-theme="light"]{--bg:#f4f7fb;--surface:#ffffff;--border:#d0d7de;--text:#1f2328;--dim:#59636e;--accent:#0a66d6;--user:#0a66d6;--ma:#1a7f37;--err:#cf222e;--hover:rgba(9,105,218,.08);--menu-bg:#e9eef5;--toolbar-bg:#f7f9fc;--shell-bg:#eef3f9;--panel-bg:#ffffff;--editor-bg:#fbfcfe;--editor-top:#eef3f8;--editor-head:#f5f8fc;--chat-bg:#ffffff;--chat-head:#f3f7fb;--input-bg:#f8fbff;--preview-bg:#ffffff;--preview-code-bg:#f2f5f9;--ide-gutter:#6e7781;--ide-line-highlight:rgba(9,105,218,.08);--tok-keyword:#cf222e;--tok-string:#0a3069;--tok-comment:#6e7781;--tok-number:#0550ae;--tok-function:#8250df;--tok-type:#953800;--tok-tag:#116329;--tok-attr:#6639ba;--tok-operator:#9a6700;color-scheme:light}
  header{background:var(--surface);border-bottom:1px solid var(--border);padding:6px 12px;display:flex;align-items:center;gap:8px;flex-shrink:0}
  header h1{font-size:14px;font-weight:600}
  header .status{font-size:11px;color:var(--dim)}
  header .dot{width:8px;height:8px;border-radius:50%;background:var(--err);display:inline-block}
  header .dot.ok{background:var(--ma)}
  .gear{cursor:pointer;font-size:18px;color:var(--dim);background:none;border:none}
  .gear:hover{color:var(--accent)}
